   299→                        "{}<{}>",
   300→                        trait_path,
   301→                        std::iter::repeat("'_")
   302→                            .take(counts.lifetimes)
   303→                            .chain(std::iter::repeat("_").take(
   304→                                counts.types + counts.consts - trait_generics.has_self as usize
   305→                            ))
   306→                            .collect::<Vec<_>>()
   307→                            .join(", ")
   308→                    )
   309→                };
