   311→            let mut self_ty_name = self_ty_span
   312→                .find_ancestor_inside(span)
   313→                .and_then(|span| self.sess().source_map().span_to_snippet(span).ok())
   314→                .unwrap_or_else(|| self_ty.to_string());
